func selectProfileForDispatch(ctx context.Context, projectRoot string, svc agentlib.FizeauService, runner AgentRunner, selector func(ProfileSnapshot) string) string {
	if selector == nil || runner != nil {
		return ""
	}
	blocking := svc != nil
	selectedSvc := svc
	if selectedSvc == nil {
		factory := serviceRunFactory
		if factory == nil {
			factory = NewServiceFromWorkDir
		}
		built, err := factory(projectRoot)
		if err != nil {
			return ""
		}
		selectedSvc = built
	}
	key := profileSnapshotProjectCacheKey(projectRoot, selectedSvc)
	if snap, ok := cachedProfileSnapshot(key); ok {
		startProfileSnapshotRefresh(key, selectedSvc)
		return selector(snap)
	}
	if blocking {
		snap, err := loadProfileSnapshot(ctx, key, selectedSvc)
		if err != nil {
			return ""
		}
		return selector(snap)
	}
	if coldCtx, cancel := profileSnapshotColdLoadContext(ctx); coldCtx != nil {
		defer cancel()
		snap, err := loadProfilePolicySnapshot(coldCtx, key, selectedSvc)
		if err == nil {
			startProfileSnapshotRefresh(key, selectedSvc)
			return selector(snap)
		}
	}
	startProfileSnapshotRefresh(key, selectedSvc)
	return ""
}

func loadProfilePolicySnapshot(ctx context.Context, key string, svc agentlib.FizeauService) (ProfileSnapshot, error) {
	profiles, err := svc.ListPolicies(ctx)
	if err != nil {
		return ProfileSnapshot{}, err
	}
	snap := ProfileSnapshot{Profiles: append([]agentlib.PolicyInfo(nil), profiles...)}

	snap := ProfileSnapshot{Profiles: append([]agentlib.PolicyInfo(nil), profiles...)}
	if key != "" {
		profileSnapshotCacheMu.Lock()
		profileSnapshotCache[key] = profileSnapshotCacheEntry{snap: cloneProfileSnapshot(snap), loadedAt: profileSnapshotNow()}
		profileSnapshotCacheMu.Unlock()
	}
	return snap, nil
}

func profileSnapshotColdLoadContext(parent context.Context) (context.Context, context.CancelFunc) {
	if profileSnapshotColdLoadTimeout <= 0 {
		if parent == nil {
			return context.Background(), func() {}
		}
		return parent, func() {}
	}
	if parent == nil {
		parent = context.Background()
	}
	return context.WithTimeout(parent, profileSnapshotColdLoadTimeout)
}

func TestAttempt_PushConflict_ParksWithCooldown(t *testing.T) {
	store := &attemptStore{}
	now := time.Date(2026, 5, 5, 10, 11, 12, 0, time.UTC)
	detail := PushConflictReasonPrefix + " auto-recovery retry push: CONFLICT (content)"

	out, err := Attempt(context.Background(), store, "ddx-test", AttemptOpts{
		Store: store,
		Executor: ExecutorFunc(func(ctx context.Context, beadID string) (Report, error) {
			return Report{
				BeadID:    beadID,
				Status:    StatusPushConflict,
				Detail:    detail,
				BaseRev:   "base",
				ResultRev: "result",
				SessionID: "session",
			}, nil
		}),
		Now: func() time.Time { return now },
	})
	require.NoError(t, err)

	assert.Equal(t, OutcomePark, out.Disposition)
	require.NotNil(t, out.Parking)
	assert.True(t, out.Parking.Unclaim)
	assert.True(t, out.Parking.RunPostAttemptTriage)
	require.NotNil(t, out.Parking.Event)
	assert.Equal(t, "push-conflict", out.Parking.Event.Kind)
	assert.Equal(t, now.Add(maxAttemptCooldown), out.Parking.RetryAfter)
	assert.Equal(t, now.Add(maxAttemptCooldown).Format(time.RFC3339), out.Report.RetryAfter)
	require.Empty(t, store.events)
	assert.Contains(t, out.Parking.Event.Body, detail)
}

func TestAttempt_RateLimit_Retry_HonorsRetryAfter(t *testing.T) {
	var sleepCalls []time.Duration
	calls := 0

	out, err := Attempt(context.Background(), nil, "ddx-test", AttemptOpts{
		Executor: ExecutorFunc(func(ctx context.Context, beadID string) (Report, error) {
			calls++
			if calls == 1 {
				return Report{
					BeadID: beadID,
					Status: StatusExecutionFailed,
					Error:  "cancelled: auth/rate-limit detected",
					Stderr: "HTTP 429\nRetry-After: 7\n",
					Detail: "rate limit",
				}, nil
			}
			return Report{BeadID: beadID, Status: StatusSuccess}, nil
		}),
		RateLimitBudget:     5 * time.Minute,
		RateLimitPerWaitCap: 60 * time.Second,
		RateLimitSleep: func(_ context.Context, d time.Duration) error {
			sleepCalls = append(sleepCalls, d)
			return nil
		},
		RateLimitNow: func() time.Time {
			return time.Date(2026, 5, 3, 12, 0, 0, 0, time.UTC)
		},
	})
	require.NoError(t, err)

	assert.Equal(t, OutcomeReported, out.Disposition)
	assert.Equal(t, StatusSuccess, out.Report.Status)
	assert.Equal(t, 2, calls)
	require.Len(t, sleepCalls, 1)
	assert.Equal(t, 7*time.Second, sleepCalls[0])
}

